       LexerForms lex;
       private List<ErrorAnalisis> syntaxErrorList;

       // conexion de parser y lexer
       public ParserForms(LexerForms lex){
           super(lex);
           this.lex = lex;
           syntaxErrorList = new ArrayList<>();
       }

       // Getters
       public LexerForms getLexer(){
           return this.lex;
       }

       public List<ErrorAnalisis> getSyntaxErrorList(){
           return this.syntaxErrorList;
       }

       //Deteccion de errores sintacticos
       public void syntax_error(Symbol s) {

            List<Integer> ids = expected_token_ids();
            List<String> list = new ArrayList<>();

            if (ids.isEmpty()) {
                    reportarErrorContextual(s);
                    return;
            }

            for (Integer id : ids) {
                list.add(traductor(symbl_name_from_id(id)));
            }

            String esperado = String.join(", ", list);

            String encontrado = (s.value != null) ? s.value.toString() : traductor(symbl_name_from_id(s.sym));

            syntaxErrorList.add(
                new ErrorAnalisis(
                    encontrado,
                    "Sintáctico",
                    "Se esperaba: " + esperado + ". Pero se encontró: '" + encontrado + "'",
                    s.left,
                    s.right
                )
            );
       }

       //Deteccion de errores en los que no se puede recuperar el analisis
       public void unrecovered_syntax_error(Symbol s) throws Exception {

           String encontrado = (s.value != null) ? s.value.toString() : traductor(symbl_name_from_id(s.sym));

           syntaxErrorList.add(new ErrorAnalisis(
                encontrado,
                "Sintáctico",
                "No se pudo recuperar el análisis cerca de: '" + encontrado + "'.",
                s.left,
                s.right
                ));
       }

        /*Metodo de inferencia de errores sintacticos (como un preventivo cuando cup no virtualiza los caracteres expected)*/
        private void reportarErrorContextual(Symbol s) {

            String tokenEncontrado = (s.value != null) ? s.value.toString() : symbl_name_from_id(s.sym);

            String mensaje = "Error de sintaxis cerca de '" + tokenEncontrado + "'. ";

            if (tokenEncontrado.equals("styles")) {

                mensaje += "Parece que olvidaste los corchetes o comas en la declaracion de estilos.";

            } else if (tokenEncontrado.equals("elements")) {

                mensaje += "Revisa que los elementos estén encerrados en llaves {} y separados por comas.";

            } else {

                mensaje += "Revisa la estructura de tu sección o configuración.";

            }
            syntaxErrorList.add(new ErrorAnalisis(tokenEncontrado, "Sintáctico", mensaje, s.left, s.right));

        }

       //Metodo que permite retornar el texto de los errores que se esperan (Escalable)
       private String traductor(String nombre) {
           switch (nombre) {
                case "IF":
                    return "' IF '";
                case "ELSE":
                    return "' ELSE '";
                case "FOR":
                    return "' FOR '";
                case "WHILE":
                    return "' WHILE '";
                case "DO":
                    return "' DO '";
                case "IGUALACION":
                    return "' = '";
                case "CORCHETE_APERTURA":
                    return "' [ '";
                case "CORCHETE_CIERRE":
                    return "' ] '";
                case "PUNTO":
                    return "' . '";
                case "DOS_PUNTOS":
                    return "' : '";
                case "COMA":
                    return "' , '";
                case "PARENT_APERTURA":
                    return "' ( '";
                case "PARENT_CIERRE":
                    return "' ) '";
                case "LABEL":
                    return "atributo 'label'";
                case "ID":
                    return "un nombre de 'variable'";
                case "ENTERO":
                    return "un numero 'entero'";
                case "EOF":
                    return "Final del Archivo";
                default:
                    return nombre.toLowerCase().replace("_", " ");

           }
       }




